-- BuilderTrend import — bt-payments batch 3 of 3  (3639 rows)
-- Run batches strictly in order.
BEGIN;
CREATE TABLE IF NOT EXISTS _bt_pay_stg (
  bt_payment_id bigint, bt_job_id bigint, bt_invoice_id bigint,
  amount numeric, payment_date date, method text, status text
);
DO $$
DECLARE r record; v_job uuid; v_inv uuid; n_ins int := 0; n_skip int := 0;
BEGIN
  FOR r IN SELECT * FROM _bt_pay_stg LOOP
    IF EXISTS (SELECT 1 FROM job_invoice_payments WHERE bt_payment_id = r.bt_payment_id) THEN
      n_skip := n_skip + 1; CONTINUE;
    END IF;
    SELECT id INTO v_inv FROM job_invoices WHERE bt_invoice_id = r.bt_invoice_id LIMIT 1;
    IF v_inv IS NULL THEN n_skip := n_skip + 1; CONTINUE; END IF;
    SELECT id INTO v_job FROM jobs WHERE bt_job_id = r.bt_job_id LIMIT 1;
      payment_date, method, status, source)
    VALUES (v_inv, v_job, r.bt_payment_id, r.amount, r.payment_date,
      r.method, r.status, 'buildertrend');
    n_ins := n_ins + 1;
  END LOOP;
  RAISE NOTICE 'job_invoice_payments imported: %, skipped (no invoice / dup): %', n_ins, n_skip;
END $$;
DROP TABLE _bt_pay_stg;
COMMIT;
